// =====================================================================
//  drivetrainPresets.ts — car -> gearbox preset catalog for the calc-gear
//  "Drivetrain" card. Picking Brand -> Model fills gear ratios + final drive +
//  gear count + redline into the GaugeCfg; the user only adds their tyre size.
//  Manual entry stays behind the "Advanced" sub-menu.
//
//  ACCURACY: calc-gear picks the gear whose rpm-per-kmh (finalDrive x ratio x
//  k_tyre) best matches live rpm/speed. RELATIVE ratio spacing (a property of
//  the TRANSMISSION) makes nearest-match land right; final drive scales all
//  gears. Ratios are documented per transmission family. Finals are the most
//  common per model - trims vary, so if the on-screen gear reads a step high/low
//  the user nudges Final drive in Advanced. Only the Volvo T8 is in-car VERIFIED.
//
//  CVT / eCVT entries (gearCount === 0, empty ratios) are LISTED so the car is
//  found in the catalog, but they have no fixed gears - selecting one only sets
//  the redline; telemetry (rpm/speed/coolant...) still works, there's just no
//  calculated gear number. transType is "MT" | "AT" | "DCT" | "AMT" | "CVT".
//
//  LIMITS: 8-speed max (firmware gearCount 1..8). 9/10-speed autos are omitted.
//  Non-monotonic dual-final DCTs were dropped (they'd mis-read). Catalog built
//  2026-07-09 by a multi-agent web sweep (manufacturer specs / ZF / gearboxlist
//  / opendbc). Every geared entry: ratios.length === gearCount, strictly falling.
// =====================================================================

export interface DrivetrainPreset {
  id: string;
  brand: string;
  model: string;
  years: string;
  trans: string;          // gearbox label (sub-line)
  transType: string;      // 'MT' | 'AT' | 'DCT' | 'AMT' | 'CVT'
  verified?: boolean;     // true = confirmed in-car (only the Volvo T8)
  gearCount: number;      // 1..8 for geared; 0 = CVT/eCVT (no fixed gears)
  ratios: number[];       // 1st..Nth, length === gearCount, strictly decreasing ([] for CVT)
  finalDrive: number;     // representative; user can override in Advanced (0 for CVT)
  redline: number;        // rpmLimit (RPM)
  shiftRpm?: number;      // shift-light default
  note?: string;
}

