/** Distinct brands, in catalog order. */
export function presetBrands(): string[] {
  const seen: string[] = [];
  for (const p of DRIVETRAIN_PRESETS) if (!seen.includes(p.brand)) seen.push(p.brand);
  return seen;
}

/** Distinct models for a brand, in catalog order. */
export function presetModels(brand: string): string[] {
  const seen: string[] = [];
  for (const p of DRIVETRAIN_PRESETS)
    if (p.brand === brand && !seen.includes(p.model)) seen.push(p.model);
  return seen;
}

/** Presets (year/trim variants) for a brand+model. */
export function presetsFor(brand: string, model: string): DrivetrainPreset[] {
  return DRIVETRAIN_PRESETS.filter((p) => p.brand === brand && p.model === model);
}

export function presetById(id: string): DrivetrainPreset | undefined {
  return DRIVETRAIN_PRESETS.find((p) => p.id === id);
}
